import { useEffect, useState } from "react";
import axios from "axios";
import { useParams, useNavigate } from "react-router-dom";
import { useMap } from "react-leaflet";

import {
  MapContainer,
  TileLayer,
  Marker,
  Popup,
  Polyline,
} from "react-leaflet";

import L from "leaflet";
import "leaflet/dist/leaflet.css";

const markerIcon = new L.Icon({
  iconUrl: "https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png",
  shadowUrl:
    "https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png",
  iconSize: [25, 41],
  iconAnchor: [12, 41],
});


function RecenterMap({ lat, lng }) {
  const map = useMap();

  useEffect(() => {
    map.setView([lat, lng], map.getZoom());
  }, [lat, lng, map]);

  return null;
}

export default function DriverRoute() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [task, setTask] = useState(null);

  const [currentLocation, setCurrentLocation] = useState({
    lat: 23.2167,
    lng: 77.4061,
  });

  const getTask = async () => {
    try {
      const res = await axios.get(
        "http://localhost:3000/api/driver/today-task"
      );

      const found = res.data.requests.find(
        (item) => item._id === id
      );

      setTask(found);
    } catch (error) {
      console.log(error);
    }
  };

  useEffect(() => {
    getTask();

    const watchId = navigator.geolocation.watchPosition(
      (position) => {
        setCurrentLocation({
          lat: position.coords.latitude,
          lng: position.coords.longitude,
        });
      },
      (error) => {
        console.log(error);
      },
      {
        enableHighAccuracy: true,
        maximumAge: 0,
        timeout: 5000,
      }
    );

    return () => {
      navigator.geolocation.clearWatch(watchId);
    };
  }, []);

  const markArrived = async () => {
    try {
      const res = await axios.put(
        `http://localhost:3000/api/driver/arrived/${id}`
      );

      setTask(res.data.data);
    } catch (error) {
      console.log(error);
    }
  };

  const markCompleted = async () => {
    try {
      const res = await axios.put(
        `http://localhost:3000/api/driver/completed/${id}`
      );

      setTask(res.data.data);

      setTimeout(() => {
        navigate("/driver-dashboard");
      }, 2000);
    } catch (error) {
      console.log(error);
    }
  };

  if (!task) {
    return (
      <div className="min-h-screen flex justify-center items-center">
        Loading...
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#4CBB17]/10">

      {/* Header */}
      <div className="bg-green-700 text-white py-4 shadow">
        <h1 className="text-center text-2xl font-bold">
          🚛 Live Route Tracking
        </h1>
      </div>

      {/* Route Info */}
      <div className="bg-white p-4 shadow">
        <p className="font-semibold">
          📍 Driver Location (Live)
        </p>

        <p className="text-sm text-gray-600">
          Latitude: {currentLocation.lat}
        </p>

        <p className="text-sm text-gray-600">
          Longitude: {currentLocation.lng}
        </p>

        <p className="mt-3 font-semibold">
          🎯 Destination: {task.location?.location}
        </p>
      </div>

      {/* Live Map */}
      <div className="h-[450px] w-full">
        <MapContainer
          center={[
            currentLocation.lat,
            currentLocation.lng,
          ]}
          zoom={14}
          style={{
            height: "100%",
            width: "100%",
          }}
        >
          <TileLayer
            attribution="OpenStreetMap"
            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          />

          {/* Driver Marker */}
          <Marker
            position={[
              currentLocation.lat,
              currentLocation.lng,
            ]}
            icon={markerIcon}
          >
            <Popup>
              🚛 Driver Live Location
            </Popup>
          </Marker>

          {/* Destination Marker */}
          <Marker
            position={[
              task.location?.latitude,
              task.location?.longitude,
            ]}
            icon={markerIcon}
          >
            <Popup>
              📍 {task.location?.location}
            </Popup>
          </Marker>

          {/* Route Line */}
          <Polyline
            positions={[
              [
                currentLocation.lat,
                currentLocation.lng,
              ],
              [
                task.location?.latitude,
                task.location?.longitude,
              ],
            ]}
          />
        </MapContainer>
      </div>

      {/* Times */}
      <div className="flex flex-col items-center mt-6">

        {task.arrivedAt && (
          <div className="bg-yellow-100 p-4 rounded-xl mb-4 w-80 text-center shadow">
            <p className="font-bold">
              Arrived Time
            </p>

            <p>
              {new Date(
                task.arrivedAt
              ).toLocaleString()}
            </p>
          </div>
        )}

        {task.completedAt && (
          <div className="bg-green-100 p-4 rounded-xl mb-4 w-80 text-center shadow">
            <p className="font-bold">
              Completed Time
            </p>

            <p>
              {new Date(
                task.completedAt
              ).toLocaleString()}
            </p>
          </div>
        )}

        {task.status === "Scheduled" && (
          <button
            onClick={markArrived}
            className="bg-yellow-500 text-white px-12 py-4 rounded-xl text-xl font-bold"
          >
            Arrived
          </button>
        )}

        {task.status === "Arrived" && (
          <button
            onClick={markCompleted}
            className="bg-green-600 text-white px-12 py-4 rounded-xl text-xl font-bold"
          >
            Completed
          </button>
        )}

      </div>
    </div>
  );
}
